@GetMapping("/exibir")
    public List<Cliente> getClientes(){
        Iterable<Cliente> clientesIterable = clienteRepository.findAll();
        List<Cliente> clientesList = new ArrayList<>();
        clientesIterable.forEach(clientesList::add);
        return clientesList;
    }

